import psycopg2

def connect_db():
    conn = psycopg2.connect(
        dbname="your_database", 
        user="your_username", 
        password="your_password", 
        host="your_host", 
        port="your_port"
    )
    return conn

def search_users(username=None, email=None, role=None, status=None):
    conn = connect_db()
    cursor = conn.cursor()
    
    query = "SELECT * FROM users WHERE true"
    params = []
    
    if username is not None:
        query += " AND username = %s"
        params.append(username)

    if email is not None:
        query += " AND email = %s"
        params.append(email)

    if role is not None:
        query += " AND role = %s"
        params.append(role)

    if status is not None:
        query += " AND status = %s"
        params.append(status)

    cursor.execute(query, tuple(params))

    user_profiles = cursor.fetchall()

    cursor.close()
    conn.close()

    return user_profiles